    inline bool Find(const char* name, std::string& out) noexcept
    {
        for (const Icon& ic : kIcons)
        {
            if (std::strcmp(ic.name, name) == 0)
            {
                out.clear();
                for (int i = 0; i < ic.partCount; ++i)
                    out += ic.parts[i];
                return true;
            }
        }
        return false;
    }
